15	interface QuoteResult {
16	  premium: number;
17	}
18	
19	const PROCESSING_FEE = 5;
20	const FIRST_INSURANCE_RATE = 0.1;
21	
22	const BASE_PREMIUM: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	  potion: 40,
27	};
28	
29	const itemPremium = (item: Item): number => {
30	  const base = BASE_PREMIUM[item.type];
31	  return base + base * FIRST_INSURANCE_RATE;
32	};
33	
34	const quoteStep = (step: QuoteStep): QuoteResult => {
35	  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
36	  return { premium: itemsTotal + PROCESSING_FEE };
37	};
38	
39	export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
40	  const results = scenario.steps.map(quoteStep);
41	  return { results };
42	};
